/// <summary>
///    The <c>SalesConfirmController</c> class is the helper class for the associated  report.
/// </summary>
public class ETG_AgreementProfomaConfirmController extends SrsReportRunController
{   
    ETG_AgreementConfirmationRDPContract         contract;
    ModuleSalesPurch                             moduleType;
    PurchAgreementHeader                         purchAgreementHeader;
    SalesAgreementHeader                         salesAgreementHeader;

}

Method.Source:
  protected void preRunModifyContract()
// protected void   prePromptModifyContract()
  {
      str                     reportnameLocal;
      contract = this.parmReportContract().parmRdpContract();
      this.getReportContract().parmReportCaption("@SYS316853");

      switch (args.record().TableId)
      {
          case  tableNum(SalesAgreementHeader):
              moduleType = ModuleSalesPurch::Sales;
              contract.parmModuleSalesPurch(moduleType);
              salesAgreementHeader =  args.record();
              contract.parmProfoma(NoYes::Yes);
              contract.parmSalesAgreementId(salesAgreementHeader.SalesNumberSequence);
             // contract.parmSalesAgreementId("O003SC_001013");

              if(curExt() == "O001")
              {
                  reportnameLocal = ssrsReportStr(ETG_AgreementConfirmationRptcopy1, Sales);
              }
              else
              {
                  reportnameLocal = ssrsReportStr(ETG_AgreementConfirmationRpt, Sales);
              }
              break;
          case  tableNum(PurchAgreementHeader):
              moduleType = ModuleSalesPurch::Purch; 
              contract.parmModuleSalesPurch(moduleType);
              purchAgreementHeader = args.record();
              contract.parmProfoma(NoYes::Yes);
              contract.parmPurchAgreementId(purchAgreementHeader.PurchNumberSequence);
             // contract.parmPurchAgreementId("ETC_P_012679");

             if(curExt() == "O001")
              {
                  reportnameLocal = ssrsReportStr(ETG_AgreementConfirmationRptcopy1, Purch);
              }
              else if(curExt() == "O051")
              {
                  reportnameLocal = ssrsReportStr(ETG_AgreementConfirmationRpt, Purch_O051);
              }
              else
              {
                 reportnameLocal = ssrsReportStr(ETG_AgreementConfirmationRpt, Purch);                
              }
              break;
          default:
              throw error(Error::wrongUseOfFunction(funcName()));
      }
      this.parmReportName(reportnameLocal);
      this.parmReportContract().parmReportName(this.parmReportName());
  }

/// </summary>
/// <param name="_args">
/// The <c>Args</c> object.
/// </param>
public static void main(Args _args)
{
    AgreementHeaderHistory                              agreementHeaderHistory;
    recId                                               recId;
    ModuleSalesPurch                                    moduleType;
    ETG_AgreementProfomaConfirmController agreementConfirmController = new ETG_AgreementProfomaConfirmController();

    if (_args.record())
    {
        agreementConfirmController.parmArgs(_args);

        if(curExt() == "O001")
        {
         agreementConfirmController.parmReportName(ssrsReportStr(ETG_AgreementConfirmationRptcopy1, purch));
        }
        else if(curExt() == "O051")
        {
            agreementConfirmController.parmReportName(ssrsReportStr(ETG_AgreementConfirmationRpt, Purch_O051));
        }
        else
        {
            agreementConfirmController.parmReportName(ssrsReportStr(ETG_AgreementConfirmationRpt, purch));
        }
        agreementConfirmController.parmShowDialog(false);
        agreementConfirmController.startOperation();
    }
}
